-- Benchmark data upsert (all weeks)
ON CONFLICT (week_ending, region) DO UPDATE SET
  region_name=EXCLUDED.region_name, store_count=EXCLUDED.store_count,
  net_sales=EXCLUDED.net_sales, sss_pct=EXCLUDED.sss_pct,
  ss_ticket_pct=EXCLUDED.ss_ticket_pct, avg_daily_bread=EXCLUDED.avg_daily_bread,
  online_sales_pct=EXCLUDED.online_sales_pct, third_party_sales_pct=EXCLUDED.third_party_sales_pct,
  non_loyalty_disc_pct=EXCLUDED.non_loyalty_disc_pct, loyalty_disc_pct=EXCLUDED.loyalty_disc_pct,
  loyalty_sales_pct=EXCLUDED.loyalty_sales_pct, fytd_net_sales=EXCLUDED.fytd_net_sales,
  weekly_auv=EXCLUDED.weekly_auv, avg_ticket_size=EXCLUDED.avg_ticket_size,
  fytd_avg_daily_bread=EXCLUDED.fytd_avg_daily_bread, fytd_sss_pct=EXCLUDED.fytd_sss_pct,
  fytd_ss_ticket_pct=EXCLUDED.fytd_ss_ticket_pct;
